    const artifacts = [makeArtifact({ name: "a" })];
    const planDry = generateDeletionPlan(artifacts, {}, { dryRun: true });
    expect(planDry.dryRun).toBe(true);

    const planLive = generateDeletionPlan(artifacts, {}, { dryRun: false });
